#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/stat.h>
int main(void) {
    const char *path = "/tmp/kf_create_test.txt";
    unlink(path);
    int fd = open(path, O_CREAT | O_WRONLY | O_EXCL, 0640);
    if (fd == -1) { perror("open"); return 1; }
    write(fd, "created\n", 8);
    close(fd);
    struct stat st;
    stat(path, &st);
    printf("File created\n");
    printf("Mode: %o\n", st.st_mode & 0777);
    printf("Size: %ld\n", (long)st.st_size);
    unlink(path);
    return 0;
}

